import{_ as t,o,c as r,a3 as n}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"46. Recovery Of Overpayments","description":"","frontmatter":{"title":"46. Recovery Of Overpayments","eba":"Doctors in Training 2022-2026","topics":["allowances","wages","preliminary"]},"headers":[],"relativePath":"ebas/doctors-in-training/remuneration/46-recovery-of-overpayments.md","filePath":"ebas/doctors-in-training/remuneration/46-recovery-of-overpayments.md"}'),a={name:"ebas/doctors-in-training/remuneration/46-recovery-of-overpayments.md"};function i(s,e,p,c,h,l){return o(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="_46-recovery-of-overpayments" tabindex="-1">46. Recovery Of Overpayments <a class="header-anchor" href="#_46-recovery-of-overpayments" aria-label="Permalink to &quot;46. Recovery Of Overpayments&quot;">​</a></h1><p><strong>46.1</strong> Details of overpayment</p><p>Where a Health Service determines that an overpayment has occurred, the Health Service shall provide, in writing, to the relevant Doctor:</p><p><strong>(a)</strong> the total amount of overpayment,</p><p><strong>(b)</strong> the reason, if any, for the overpayment (i.e. incorrect application of an allowance),</p><p><strong>(c)</strong> when the overpayments have occurred,</p><p><strong>(d)</strong> the scope to enter into a repayment arrangement within the limits set by the Financial Management Act 1994 (currently one tenth of the salary or wages, before any deductions),</p><p><strong>(e)</strong> propose a time to meet to discuss the overpayment,</p><p><strong>(f)</strong> advice that the Doctor is welcome to bring a representative, including a representative of the Association, to any meeting.</p><p><strong>46.2</strong> Discussion regarding overpayment</p><p>The Health Service and Doctor will meet as soon as practicable to discuss and consider:</p><p><strong>(a)</strong> whether it is agreed that the amount identified by the Health Service is an overpayment,</p><p><strong>(b)</strong> the amount of any deduction within the limits set by the Financial Management Act 1994 (currently one tenth of the salary or wages, before any deductions), and</p><p><strong>(c)</strong> any proposal put forward by the Doctor with respect to the repayment of the overpayment including any circumstances of hardship which will be dealt with in accordance with the Financial Management Act 1994.</p><p><strong>46.3</strong> Decision regarding overpayment</p><p>Following the meeting and after any proposal by the Doctor with respect to the repayment of the overpayment has been considered, the Health Service shall advise the Doctor in writing of its decision regarding repayment.</p><p><strong>46.4</strong> Dispute</p><p>Either the Health Service or Doctor may refer a dispute about an overpayment, including but not limited to the quantum of the overpayment and/or how it is to be repaid, to the Dispute Resolution clause of this Agreement.</p><p><strong>46.5</strong> Other rights</p><p>Nothing in this clause affects the rights or obligations or either party under the Financial Management Act 1994 including but not limited to:</p><p><strong>(a)</strong> The Doctor’s right to apply to the relevant Minister for the weekly amount of the deductions to be reduced, and</p><p><strong>(b)</strong> The Doctor’s right to apply in writing to the relevant Minister to be relieved from all or any of the liability with respect to the repayment of the overpayment.</p><p>Plain language terms: overpayment, clawback.</p>',23)])])}const d=t(a,[["render",i]]);export{m as __pageData,d as default};
